previewCss:
.darma-loader-darma-custom-657 { color: var(--loader-color, #d97706); --loader-secondary-color: #facc15; --loader-bg: #111827; }
@keyframes darma-loader-darma-custom-657-bounce {
  0%,
  100% {
    translate: 0px 36px;
  }
  50% {
    translate: 0px 46px;
  }
}
@keyframes darma-loader-darma-custom-657-bounce2 {
  0%,
  100% {
    translate: 0px 46px;
  }
  50% {
    translate: 0px 56px;
  }
}

@keyframes darma-loader-darma-custom-657-umbral {
  0% {
    stop-color: #d3a5102e;
  }
  50% {
    stop-color: rgba(211, 165, 16, 0.519);
  }
  100% {
    stop-color: #d3a5102e;
  }
}
@keyframes darma-loader-darma-custom-657-partciles {
  0%,
  100% {
    translate: 0px 16px;
  }
  50% {
    translate: 0px 6px;
  }
}
.darma-loader-darma-custom-657-particles {
  animation: darma-loader-darma-custom-657-partciles 4s ease-in-out infinite;
}
.darma-loader-darma-custom-657-animatedStop {
  animation: darma-loader-darma-custom-657-umbral 4s infinite;
}
#darma-loader-darma-custom-657-bounce {
  animation: darma-loader-darma-custom-657-bounce 4s ease-in-out infinite;
  translate: 0px 36px;
}
#darma-loader-darma-custom-657-bounce2 {
  animation: darma-loader-darma-custom-657-bounce2 4s ease-in-out infinite;
  translate: 0px 46px;
  animation-delay: 0.5s;
}

